<?php session_start();    class Maileur    {        private $sujet;        private $emails = Array();        private $date;        private $titre;        private $corps;        private $fichier;        private $expediteur_name;        private $expediteur_mail;        private $logo;        private $add_signature;        private $nom_signature;        private $web_signature;        private $mail_signature;        private $tel_signature;        private $doc;        private $id_doc;        private $bl;        private $id_bl;        private $body;        private $formating = true;        private $key;        public function __construct($sujet='Nouveau mail de Managy.fr')        {            $this->sujet = $sujet;            $this->fichier = False;            $this->parseDate();            $this->expediteur_name = 'Managy';            $this->expediteur_mail = 'noreply@managy.fr';            $this->logo = 'managy';            $this->add_signature = false;            $this->doc = '';        }        public function reSetSubject($sujet)        {            $this->sujet = $sujet;        }        public function withAck($id_client, $sujet, $nom_id, $valeur_id, $destinataire, $id_staff="0", $compte_principal="0")        {            //echo 'ok';            $this->key = '';            $t = new ExternalLink(250);            $this->key = $t;            if($id_staff)                $staff = $id_staff;            else                $staff = $_SESSION['id'];            if($compte_principal)                $cp = $compte_principal;            else                $cp = $_SESSION['compte_principal'];            $db = new MySQL();            $valeur_id = $db->SQLFix($valeur_id);            $nom_id = $db->SQLFix($nom_id);            $sujet = $db->SQLFix($sujet);            $cp = $db->SQLFix($cp);            $staff = $db->SQLFix($staff);            $id_client = $db->SQLFix($id_client);            $sujet = $db->SQLFix($sujet);            $destinataire = $db->SQLFix($destinataire);            $sql = 'INSERT INTO mails_with_ack (cle, id_client, id_staff, timestamp, '.$nom_id.', sujet, destinataire, compte_principal) VALUES ("'.$this->key.'", "'.$id_client.'", "'.$staff.'", "'.time().'", "'.$valeur_id.'", "'.$sujet.'", "'.$destinataire.'", "'.$cp.'") ';            echo $sql;            $db->Query($sql);            echo $db->Error();        }        public function setLogo($logo='managy')        {            $this->logo = $logo;        }        public function addExpediteur($expediteur_mail, $expediteur_name)        {            $this->expediteur_name = $expediteur_name;            $this->expediteur_mail = $expediteur_mail;        }        public function addDest($email)        {            $em = explode(',', $email);                foreach ($em AS $m)            $this->emails[] = $m;        }        private function parseDate()         {            $tab_mois = Array('Janvier', 'Février', 'Mars', 'Avril', 'Mai', 'Juin', 'Juillet', 'Août', 'Septembre', 'Octobre', 'Novembre', 'Décembre');            $mois = $tab_mois[date('n') - 1];            $jour = date('d');            $annee = date('Y');            $this->date = $jour.' '.$mois.' '.$annee;        }        public function body($body)        {            $this->corps = $body;        }        public function AddTitle($titre)        {            $this->titre = $titre;        }        public function addSignature($nom, $web, $mail, $tel)        {            $this->add_signature = true;            $this->nom_signature = $nom;            $this->web_signature = $web;            $this->mail_signature = $mail;            $this->tel_signature = $tel;        }        public function addBl($pdf_id)        {            $_GET['id_bl'] = $pdf_id;            $send_mail = true;            include('./../pdf_bl.php');            $this->bl = $doc;            $this->id_bl = $pdf_id;        }        public function addOfPeinture($id)        {            $_GET['id_inter'] = $id;            $send_mail = true;            include('./pdf_of.php');            $this->doc = $doc;            $this->id_doc = $id;        }        public function noFormating()        {            $this->formating = false;        }        public function getBody()        {            return $this->body;        }        public function send()        {            if($this->formating)            {                $dossier = getcwd();                $tab_dossier = explode('/', $dossier);                $current = $tab_dossier[count($tab_dossier) - 1];                if ($current != 'managy') {                    $file = './../templates/mail/IdeaMail/Blue/Dark-Background/Layout5.php';                    require_once('./../classes/PhpMailer/PHPMailerAutoload.php');                } else {                    $file = './templates/mail/IdeaMail/Blue/Dark-Background/Layout5.php';                }                if (is_file($file)) {                    if (empty($this->titre))                        $titre = $this->sujet;                    else                        $titre = $this->titre;                    $corps = $this->corps;                    $date = $this->date;                    $logo = $this->logo;                    $add_signature = $this->add_signature;                    $nom_signature = $this->nom_signature;                    $web_signature = $this->web_signature;                    $mail_signature = $this->mail_signature;                    $tel_signature = $this->tel_signature;                    $key = $this->key;                    ob_start();                    include($file);                    $content = utf8_decode(ob_get_contents());                    ob_end_clean();                    $this->body = $content;                    $headers = 'From: "' . $this->expediteur_name . '"<' . $this->expediteur_mail . '>' . "\n";                    if ($this->fichier)                        $headers .= 'Content-Type: multipart/mixed; charset="utf-8"' . "\n";                    else                        $headers .= 'Content-Type: text/html; charset="utf-8"' . "\n";                    foreach ($this->emails AS $adresse_mail) {                        //mail($mail, $this->sujet, $content, $headers);                        //Create a new PHPMailer instance                        $mail = new PHPMailer;                        // Set PHPMailer to use the sendmail transport                        $mail->isSendmail();                        $mail->charSet = "UTF-8";                        //$mail->addCustomHeader($headers);                        //Set who the message is to be sent from                        $mail->setFrom($this->expediteur_mail, utf8_decode($this->expediteur_name));                        //Set an alternative reply-to address                        //Set who the message is to be sent to                        $mail->addAddress($adresse_mail);                        //Set the subject line                        $mail->Subject = utf8_decode($this->sujet);                        //Read an HTML message body from an external file, convert referenced images to embedded,                        //convert HTML into a basic plain-text alternative body                        $mail->msgHTML($content);                        //Attach an image file                        if ($this->id_doc)                            $mail->AddStringAttachment($this->doc, 'fiche-of-peinture-' . $this->id_doc . '.pdf', 'base64', 'application/pdf');                        if ($this->id_bl)                            $mail->AddStringAttachment($this->bl,  'bl-'.$this->id_bl.'.pdf','base64','application/pdf');                        $mail->send();                    }                }            }            else // PAs de formatage            {                $headers = 'From: "' . $this->expediteur_name . '"<' . $this->expediteur_mail . '>' . "\n";                if ($this->fichier)                    $headers .= 'Content-Type: multipart/mixed; charset="utf-8"' . "\n";                else                    $headers .= 'Content-Type: text/html; charset="utf-8"' . "\n";                foreach ($this->emails AS $adresse_mail) {                    //mail($mail, $this->sujet, $content, $headers);                    //Create a new PHPMailer instance                    $mail = new PHPMailer;                    // Set PHPMailer to use the sendmail transport                    $mail->isSendmail();                    $mail->charSet = "UTF-8";                    //Set who the message is to be sent from                    $mail->setFrom($this->expediteur_mail, utf8_decode($this->expediteur_name));                    //Set an alternative reply-to address                    //Set who the message is to be sent to                    $mail->addAddress($adresse_mail);                    //Set the subject line                    $mail->Subject = utf8_decode($this->sujet);                    //Read an HTML message body from an external file, convert referenced images to embedded,                    //convert HTML into a basic plain-text alternative body                    $mail->msgHTML($this->corps);                    if($mail->send())                        echo 'ok';                    else                        echo $mail->ErrorInfo;                }            }        }    };?>